import React from 'react';
import './world-map.css';
import BattleMode from '../battle-mode/battle-mode';
import mapsData from './maps.json';
import map1 from './louth.json';
import map2 from './louth2.json';
import map3 from './louth.json';

const maps = [map1.mapData, map2.mapData, map3.mapData];

class Overworld extends React.Component {
  constructor(props) {
    super(props);

    this.state = {
      playerPosition: {
        row: 0,
        col: 0,
      },
      badGuyPosition: {
        row: 5,
        col: 5,
      },
      message: '',
      remainingMoves: 2,
      isBadGuyMoving: false,
      selectedMapIndex: 0,
      currentCountyIndex: 0,
      currentMap: map1.mapData,
    };
  }

  handleMapButtonClick = (mapData) => {
    this.setState({
      currentMap: mapData,
    });
  };

  componentDidMount() {
    this.updateMessage();
    window.addEventListener('resize', this.handleResize);
  }

  componentWillUnmount() {
    window.removeEventListener('resize', this.handleResize);
  }

  // ... (other methods)

  renderGameBoard() {
    const { playerPosition, badGuyPosition, currentMap } = this.state;

    return currentMap.map((row, rowIndex) => (
      <div key={`row-${rowIndex}`} className="game-row">
        {/* ... (row rendering logic) */}
      </div>
    ));
  }

  render() {
    const { currentMap } = this.state;
    const { message, isBadGuyMoving, playerPosition, currentCountyIndex } = this.state;
    const currentCounty = mapsData[currentCountyIndex];

    return (
      <div className="world-map-container">
        <h1>{message}</h1>
        {/* ... (other JSX elements) */}
        <button onClick={() => this.handleMapButtonClick(map2.mapData)}>Toggle Map</button>
        <div className="world-map">
          {this.renderGameBoard()}
          {/* ... (battle mode rendering logic) */}
        </div>
        <button onClick={this.endTurn} disabled={isBadGuyMoving}>
          End Turn
        </button>
      </div>
    );
  }
}

export default Overworld;
